import React, { useState, useEffect } from 'react';
import io from 'socket.io-client';
import './App.css';

const socket = io('http://localhost:4000');

function App() {
  const [gameState, setGameState] = useState({
    board: Array(9).fill(null),
    currentPlayer: 'X',
    winner: null,
    players: {
      X: { name: null, socketId: null },
      O: { name: null, socketId: null }
    },
    gameStarted: false
  });
  const [player, setPlayer] = useState(null);
  const [playerName, setPlayerName] = useState('');
  const [nameSubmitted, setNameSubmitted] = useState(false);

  useEffect(() => {
    socket.on('playerAssigned', ({ player }) => {
      setPlayer(player);
    });

    socket.on('gameState', (newGameState) => {
      setGameState(newGameState);
    });

    socket.on('gameFull', () => {
      alert('Game is full. Please try again later.');
    });

    return () => {
      socket.off('playerAssigned');
      socket.off('gameState');
      socket.off('gameFull');
    };
  }, []);

  const handleNameSubmit = (e) => {
    e.preventDefault();
    if (playerName.trim()) {
      socket.emit('setName', playerName.trim());
      setNameSubmitted(true);
    }
  };

  const handleClick = (index) => {
    if (gameState.board[index] || gameState.winner || gameState.currentPlayer !== player) return;
    socket.emit('makeMove', index);
  };

  const resetGame = () => {
    socket.emit('resetGame');
  };

  const getWinningLine = (board) => {
    const lines = [
      [0, 1, 2],
      [3, 4, 5],
      [6, 7, 8],
      [0, 3, 6],
      [1, 4, 7],
      [2, 5, 8],
      [0, 4, 8],
      [2, 4, 6],
    ];

    for (let line of lines) {
      const [a, b, c] = line;
      if (board[a] && board[a] === board[b] && board[a] === board[c]) {
        return line;
      }
    }
    return null;
  };

  const winningLine = getWinningLine(gameState.board);

  const renderSquare = (index) => {
    const highlight = winningLine && winningLine.includes(index) ? 'highlight' : '';
    return (
      <button className={`square ${highlight}`} onClick={() => handleClick(index)}>
        {gameState.board[index]}
      </button>
    );
  };

  if (!player) {
    return (
      <div className="App">
        <h1>Waiting for player assignment...</h1>
      </div>
    );
  }

  if (!nameSubmitted) {
    return (
      <div className="App">
        <h1>You are Player {player}</h1>
        <form onSubmit={handleNameSubmit}>
          <label>
            Enter your name:
            <input
              type="text"
              value={playerName}
              onChange={(e) => setPlayerName(e.target.value)}
              required
            />
          </label>
          <button type="submit">Start Game</button>
        </form>
      </div>
    );
  }

  const status = gameState.winner
    ? gameState.winner === 'Draw'
      ? 'Game is a Draw!'
      : `Winner: ${gameState.players[gameState.winner]?.name || gameState.winner}`
    : `Next player: ${gameState.players[gameState.currentPlayer]?.name || gameState.currentPlayer}`;

  const currentPlayerClass = `current-player ${gameState.currentPlayer}`;

  return (
    <div className="App">
      <header>
        <h1 className="title">Tic Tac Toe</h1>
        <div className="players">
          <p>Player X: {gameState.players.X.name || 'Waiting...'}</p>
          <p>Player O: {gameState.players.O.name || 'Waiting...'}</p>
        </div>
      </header>
      <div className="status">
        {gameState.winner ? (
          status
        ) : (
          <>Next player: <span className={currentPlayerClass}>{gameState.players[gameState.currentPlayer]?.name || gameState.currentPlayer}</span></>
        )}
      </div>
      <div className="board">
        <div className="board-row">
          {renderSquare(0)}
          {renderSquare(1)}
          {renderSquare(2)}
        </div>
        <div className="board-row">
          {renderSquare(3)}
          {renderSquare(4)}
          {renderSquare(5)}
        </div>
        <div className="board-row">
          {renderSquare(6)}
          {renderSquare(7)}
          {renderSquare(8)}
        </div>
      </div>
      <button onClick={resetGame}>Reset Game</button>
    </div>
  );
}

export default App;
